from itertools import count
from collections import deque
from sympy import factorint
def A396215(n):
    a = deque([sum(factorint(i).values()) for i in range(1,n+1)])
    b = n+sum(a)
    for k in count(n+1):
        if sum(a)==b:
            return k-n
        a.popleft()
        a.append(sum(factorint(k).values())) # _Chai Wah Wu_, May 21 2026

